class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert(root, value):
    if root is None:
        return Node(value)
    if value < root.value:
        root.left = insert(root.left, value)
    elif value > root.value:
        root.right = insert(root.right, value)
    return root

def process_chars_recursive(sequence, index, root, seen):
    if index >= len(sequence):
        return root

    char = sequence[index].lower()

    if char not in seen:
        seen.add(char)
        root = insert(root, char)

    return process_chars_recursive(sequence, index + 1, root, seen)

